(function () {
  'use strict';

  var modal;
  var previewImage;
  var helperText;
  var shareButton;
  var copyImageButton;
  var copyLinkButton;
  var activeDataUrl = '';
  var activeShareFile = null;
  var activeData = null;
  var lastFocus = null;
  var toastTimer = 0;

  var QR_BLOCKS_L = {
    1: { ec: 7, data: [19] },
    2: { ec: 10, data: [34] },
    3: { ec: 15, data: [55] },
    4: { ec: 20, data: [80] },
    5: { ec: 26, data: [108] },
    6: { ec: 18, data: [68, 68] },
    7: { ec: 20, data: [78, 78] },
    8: { ec: 24, data: [97, 97] },
    9: { ec: 30, data: [116, 116] },
    10: { ec: 18, data: [68, 68, 69, 69] }
  };

  var ALIGNMENT_POSITIONS = {
    1: [],
    2: [6, 18],
    3: [6, 22],
    4: [6, 26],
    5: [6, 30],
    6: [6, 34],
    7: [6, 22, 38],
    8: [6, 24, 42],
    9: [6, 26, 46],
    10: [6, 28, 50]
  };

  var GF_EXP = new Array(512);
  var GF_LOG = new Array(256);

  function initGaloisField() {
    var value = 1;
    for (var i = 0; i < 255; i++) {
      GF_EXP[i] = value;
      GF_LOG[value] = i;
      value <<= 1;
      if (value & 0x100) value ^= 0x11d;
    }
    for (var j = 255; j < 512; j++) {
      GF_EXP[j] = GF_EXP[j - 255];
    }
  }

  function gfMultiply(a, b) {
    return a === 0 || b === 0 ? 0 : GF_EXP[GF_LOG[a] + GF_LOG[b]];
  }

  function rsGenerator(degree) {
    var poly = [1];
    for (var i = 0; i < degree; i++) {
      var next = new Array(poly.length + 1).fill(0);
      for (var j = 0; j < poly.length; j++) {
        next[j] ^= poly[j];
        next[j + 1] ^= gfMultiply(poly[j], GF_EXP[i]);
      }
      poly = next;
    }
    return poly;
  }

  function rsRemainder(data, degree) {
    var generator = rsGenerator(degree);
    var result = new Array(degree).fill(0);
    data.forEach(function (value) {
      var factor = value ^ result[0];
      result.shift();
      result.push(0);
      for (var i = 0; i < degree; i++) {
        result[i] ^= gfMultiply(generator[i + 1], factor);
      }
    });
    return result;
  }

  function utf8Bytes(text) {
    if (window.TextEncoder) {
      return Array.prototype.slice.call(new TextEncoder().encode(text));
    }
    var encoded = unescape(encodeURIComponent(text));
    var bytes = [];
    for (var i = 0; i < encoded.length; i++) bytes.push(encoded.charCodeAt(i));
    return bytes;
  }

  function BitBuffer() {
    this.bits = [];
  }

  BitBuffer.prototype.append = function (value, length) {
    for (var i = length - 1; i >= 0; i--) {
      this.bits.push(((value >>> i) & 1) === 1);
    }
  };

  BitBuffer.prototype.toBytes = function () {
    var bytes = [];
    for (var i = 0; i < this.bits.length; i += 8) {
      var value = 0;
      for (var j = 0; j < 8; j++) {
        value = (value << 1) | (this.bits[i + j] ? 1 : 0);
      }
      bytes.push(value);
    }
    return bytes;
  };

  function chooseVersion(dataLength) {
    for (var version = 1; version <= 10; version++) {
      var block = QR_BLOCKS_L[version];
      var capacity = block.data.reduce(function (sum, item) { return sum + item; }, 0);
      var lengthBits = version < 10 ? 8 : 16;
      var neededBits = 4 + lengthBits + dataLength * 8;
      if (neededBits <= capacity * 8) return version;
    }
    throw new Error('文章链接过长，无法生成二维码。');
  }

  function createDataCodewords(text, version) {
    var bytes = utf8Bytes(text);
    var block = QR_BLOCKS_L[version];
    var capacity = block.data.reduce(function (sum, item) { return sum + item; }, 0);
    var buffer = new BitBuffer();
    buffer.append(4, 4);
    buffer.append(bytes.length, version < 10 ? 8 : 16);
    bytes.forEach(function (value) {
      buffer.append(value, 8);
    });
    var remaining = capacity * 8 - buffer.bits.length;
    buffer.append(0, Math.min(4, remaining));
    while (buffer.bits.length % 8 !== 0) buffer.bits.push(false);
    var padBytes = [0xec, 0x11];
    var padIndex = 0;
    while (buffer.bits.length < capacity * 8) {
      buffer.append(padBytes[padIndex % 2], 8);
      padIndex++;
    }
    return buffer.toBytes();
  }

  function createCodewords(text) {
    var bytes = utf8Bytes(text);
    var version = chooseVersion(bytes.length);
    var blockInfo = QR_BLOCKS_L[version];
    var dataCodewords = createDataCodewords(text, version);
    var offset = 0;
    var dataBlocks = blockInfo.data.map(function (length) {
      var block = dataCodewords.slice(offset, offset + length);
      offset += length;
      return block;
    });
    var eccBlocks = dataBlocks.map(function (block) {
      return rsRemainder(block, blockInfo.ec);
    });
    var result = [];
    var maxDataLength = Math.max.apply(null, blockInfo.data);
    for (var i = 0; i < maxDataLength; i++) {
      dataBlocks.forEach(function (block) {
        if (i < block.length) result.push(block[i]);
      });
    }
    for (var j = 0; j < blockInfo.ec; j++) {
      eccBlocks.forEach(function (block) {
        result.push(block[j]);
      });
    }
    return { version: version, codewords: result };
  }

  function createQrMatrix(text) {
    var payload = createCodewords(text);
    var version = payload.version;
    var size = version * 4 + 17;
    var modules = makeMatrix(size, null);
    var isFunction = makeMatrix(size, false);
    drawFunctionPatterns(modules, isFunction, version);
    var bestModules = null;
    var bestPenalty = Infinity;
    for (var mask = 0; mask < 8; mask++) {
      var candidate = cloneMatrix(modules);
      drawCodewords(candidate, isFunction, payload.codewords, mask);
      drawFormatBits(candidate, isFunction, mask);
      var penalty = calculatePenalty(candidate);
      if (penalty < bestPenalty) {
        bestPenalty = penalty;
        bestModules = candidate;
      }
    }
    return bestModules;
  }

  function makeMatrix(size, value) {
    var matrix = [];
    for (var y = 0; y < size; y++) {
      var row = [];
      for (var x = 0; x < size; x++) row.push(value);
      matrix.push(row);
    }
    return matrix;
  }

  function cloneMatrix(matrix) {
    return matrix.map(function (row) { return row.slice(); });
  }

  function setFunctionModule(modules, isFunction, x, y, value) {
    modules[y][x] = value;
    isFunction[y][x] = true;
  }

  function drawFunctionPatterns(modules, isFunction, version) {
    var size = modules.length;
    drawFinder(modules, isFunction, 3, 3);
    drawFinder(modules, isFunction, size - 4, 3);
    drawFinder(modules, isFunction, 3, size - 4);
    for (var i = 8; i < size - 8; i++) {
      setFunctionModule(modules, isFunction, i, 6, i % 2 === 0);
      setFunctionModule(modules, isFunction, 6, i, i % 2 === 0);
    }
    var alignments = ALIGNMENT_POSITIONS[version];
    alignments.forEach(function (x) {
      alignments.forEach(function (y) {
        var nearFinder = (x === 6 && y === 6) || (x === 6 && y === size - 7) || (x === size - 7 && y === 6);
        if (!nearFinder) drawAlignment(modules, isFunction, x, y);
      });
    });
    drawFormatBits(modules, isFunction, 0);
    if (version >= 7) drawVersionBits(modules, isFunction, version);
    setFunctionModule(modules, isFunction, 8, size - 8, true);
  }

  function drawFinder(modules, isFunction, cx, cy) {
    var size = modules.length;
    for (var dy = -4; dy <= 4; dy++) {
      for (var dx = -4; dx <= 4; dx++) {
        var x = cx + dx;
        var y = cy + dy;
        if (x < 0 || x >= size || y < 0 || y >= size) continue;
        var dist = Math.max(Math.abs(dx), Math.abs(dy));
        setFunctionModule(modules, isFunction, x, y, dist === 3 || dist <= 1);
      }
    }
  }

  function drawAlignment(modules, isFunction, cx, cy) {
    for (var dy = -2; dy <= 2; dy++) {
      for (var dx = -2; dx <= 2; dx++) {
        var dist = Math.max(Math.abs(dx), Math.abs(dy));
        setFunctionModule(modules, isFunction, cx + dx, cy + dy, dist === 2 || dist === 0);
      }
    }
  }

  function drawCodewords(modules, isFunction, codewords, mask) {
    var size = modules.length;
    var bitIndex = 0;
    var upward = true;
    for (var right = size - 1; right >= 1; right -= 2) {
      if (right === 6) right--;
      for (var vert = 0; vert < size; vert++) {
        var y = upward ? size - 1 - vert : vert;
        for (var j = 0; j < 2; j++) {
          var x = right - j;
          if (isFunction[y][x]) continue;
          var bit = false;
          if (bitIndex < codewords.length * 8) {
            bit = ((codewords[Math.floor(bitIndex / 8)] >>> (7 - (bitIndex % 8))) & 1) === 1;
            bitIndex++;
          }
          modules[y][x] = bit !== shouldMask(mask, x, y);
        }
      }
      upward = !upward;
    }
  }

  function shouldMask(mask, x, y) {
    switch (mask) {
      case 0: return (x + y) % 2 === 0;
      case 1: return y % 2 === 0;
      case 2: return x % 3 === 0;
      case 3: return (x + y) % 3 === 0;
      case 4: return (Math.floor(y / 2) + Math.floor(x / 3)) % 2 === 0;
      case 5: return ((x * y) % 2 + (x * y) % 3) === 0;
      case 6: return (((x * y) % 2 + (x * y) % 3) % 2) === 0;
      case 7: return (((x + y) % 2 + (x * y) % 3) % 2) === 0;
      default: return false;
    }
  }

  function drawFormatBits(modules, isFunction, mask) {
    var size = modules.length;
    var bits = getFormatBits(mask);
    for (var i = 0; i <= 5; i++) setFunctionModule(modules, isFunction, 8, i, getBit(bits, i));
    setFunctionModule(modules, isFunction, 8, 7, getBit(bits, 6));
    setFunctionModule(modules, isFunction, 8, 8, getBit(bits, 7));
    setFunctionModule(modules, isFunction, 7, 8, getBit(bits, 8));
    for (var j = 9; j < 15; j++) setFunctionModule(modules, isFunction, 14 - j, 8, getBit(bits, j));
    for (var k = 0; k < 8; k++) setFunctionModule(modules, isFunction, size - 1 - k, 8, getBit(bits, k));
    for (var m = 8; m < 15; m++) setFunctionModule(modules, isFunction, 8, size - 15 + m, getBit(bits, m));
    setFunctionModule(modules, isFunction, 8, size - 8, true);
  }

  function drawVersionBits(modules, isFunction, version) {
    var size = modules.length;
    var bits = getBchBits(version, 0x1f25, 12);
    for (var i = 0; i < 18; i++) {
      var bit = getBit(bits, i);
      var a = size - 11 + (i % 3);
      var b = Math.floor(i / 3);
      setFunctionModule(modules, isFunction, a, b, bit);
      setFunctionModule(modules, isFunction, b, a, bit);
    }
  }

  function getFormatBits(mask) {
    var data = (1 << 3) | mask;
    return getBchBits(data, 0x537, 10) ^ 0x5412;
  }

  function getBchBits(data, divisor, shift) {
    var value = data << shift;
    while (bitLength(value) >= bitLength(divisor)) {
      value ^= divisor << (bitLength(value) - bitLength(divisor));
    }
    return (data << shift) | value;
  }

  function bitLength(value) {
    var length = 0;
    while (value !== 0) {
      length++;
      value >>>= 1;
    }
    return length;
  }

  function getBit(value, index) {
    return ((value >>> index) & 1) !== 0;
  }

  function calculatePenalty(modules) {
    var size = modules.length;
    var penalty = 0;
    for (var y = 0; y < size; y++) penalty += runPenalty(modules[y]);
    for (var x = 0; x < size; x++) {
      var column = [];
      for (var yy = 0; yy < size; yy++) column.push(modules[yy][x]);
      penalty += runPenalty(column);
    }
    for (var row = 0; row < size - 1; row++) {
      for (var col = 0; col < size - 1; col++) {
        var color = modules[row][col];
        if (color === modules[row][col + 1] && color === modules[row + 1][col] && color === modules[row + 1][col + 1]) {
          penalty += 3;
        }
      }
    }
    var dark = 0;
    modules.forEach(function (rowItems) {
      rowItems.forEach(function (item) {
        if (item) dark++;
      });
    });
    penalty += Math.floor(Math.abs(dark * 20 - size * size * 10) / (size * size)) * 10;
    return penalty;
  }

  function runPenalty(items) {
    var penalty = 0;
    var runColor = items[0];
    var runLength = 1;
    for (var i = 1; i < items.length; i++) {
      if (items[i] === runColor) {
        runLength++;
      } else {
        if (runLength >= 5) penalty += runLength - 2;
        runColor = items[i];
        runLength = 1;
      }
    }
    if (runLength >= 5) penalty += runLength - 2;
    return penalty;
  }

  function getPostData(widget) {
    var json = widget.querySelector('.share-card-data');
    if (!json) return null;
    try {
      var data = JSON.parse(json.textContent);
      data.url = normalizeUrl(data.url || window.location.href);
      data.siteTitle = data.siteTitle || "Le's Blog";
      data.siteUrl = normalizeSiteUrl(data.siteUrl || window.location.origin);
      data.categories = Array.isArray(data.categories) ? data.categories : [];
      data.tags = Array.isArray(data.tags) ? data.tags : [];
      return data;
    } catch (err) {
      return null;
    }
  }

  function normalizeUrl(url) {
    var clean = url.replace(/index\.html$/i, '');
    try {
      return decodeURI(clean);
    } catch (err) {
      return clean;
    }
  }

  function normalizeSiteUrl(url) {
    return url.replace(/^https?:\/\//, '').replace(/\/$/, '');
  }

  function ensureModal() {
    if (modal) return;
    modal = document.createElement('div');
    modal.className = 'share-card-modal';
    modal.setAttribute('role', 'dialog');
    modal.setAttribute('aria-modal', 'true');
    modal.setAttribute('aria-labelledby', 'share-card-modal-title');
    modal.innerHTML = [
      '<div class="share-card-modal__backdrop" data-share-card-close></div>',
      '<div class="share-card-modal__panel">',
      '<div class="share-card-modal__head">',
      '<div class="share-card-modal__title" id="share-card-modal-title">分享卡片预览</div>',
      '<button class="share-card-modal__close" type="button" aria-label="关闭分享卡片" data-share-card-close>&times;</button>',
      '</div>',
      '<div class="share-card-modal__body">',
      '</div>',
      '<div class="share-card-modal__actions">',
      '<button class="share-card-action share-card-action--primary" type="button" data-share-card-copy-image>复制图片</button>',
      '<button class="share-card-action share-card-action--secondary" type="button" data-share-card-native>直接分享</button>',
      '<button class="share-card-action share-card-action--secondary" type="button" data-share-card-copy>复制链接</button>',
      '</div>',
      '</div>'
    ].join('');
    previewImage = document.createElement('img');
    previewImage.className = 'share-card-preview';
    previewImage.alt = '文章分享卡片预览';
    modal.querySelector('.share-card-modal__body').appendChild(previewImage);
    helperText = document.createElement('p');
    helperText.className = 'share-card-modal__hint';
    modal.querySelector('.share-card-modal__body').appendChild(helperText);
    shareButton = modal.querySelector('[data-share-card-native]');
    copyImageButton = modal.querySelector('[data-share-card-copy-image]');
    copyLinkButton = modal.querySelector('[data-share-card-copy]');
    modal.addEventListener('click', function (event) {
      if (event.target.hasAttribute('data-share-card-close')) closeModal();
      if (event.target.hasAttribute('data-share-card-native')) shareCardImage();
      if (event.target.hasAttribute('data-share-card-copy-image')) copyCardImage();
      if (event.target.hasAttribute('data-share-card-copy')) copyLink();
    });
    document.body.appendChild(modal);
  }

  function openModal(data, trigger) {
    ensureModal();
    lastFocus = trigger;
    activeData = data;
    activeDataUrl = renderShareCard(data);
    activeShareFile = dataUrlToFile(activeDataUrl, filenameFromTitle(data.title || 'share-card') + '.png');
    previewImage.src = activeDataUrl;
    updateNativeShareState();
    updateCopyImageState();
    updateActionPriority();
    updateHelperText();
    modal.classList.add('is-open');
    document.documentElement.style.overflow = 'hidden';
    var closeButton = modal.querySelector('.share-card-modal__close');
    if (closeButton) closeButton.focus();
  }

  function closeModal() {
    if (!modal) return;
    modal.classList.remove('is-open');
    document.documentElement.style.overflow = '';
    if (lastFocus && typeof lastFocus.focus === 'function') lastFocus.focus();
  }

  function canShareImageFile() {
    if (!navigator.share || !navigator.canShare || !activeShareFile) return false;
    try {
      return navigator.canShare({ files: [activeShareFile] });
    } catch (err) {
      return false;
    }
  }

  function updateNativeShareState() {
    if (!shareButton) return;
    var supported = canShareImageFile();
    shareButton.disabled = !supported;
    shareButton.setAttribute('aria-disabled', supported ? 'false' : 'true');
    shareButton.title = supported ? '调用系统分享面板分享卡片图片' : (isMobileLike() ? '当前浏览器暂不支持直接分享图片，请长按卡片图片保存' : '当前浏览器暂不支持直接分享图片，请复制图片或链接分享');
  }

  function canCopyImageFile() {
    return !isMobileLike() && Boolean(navigator.clipboard && navigator.clipboard.write && window.ClipboardItem && activeShareFile);
  }

  function updateCopyImageState() {
    if (!copyImageButton) return;
    var mobile = isMobileLike();
    var supported = canCopyImageFile();
    copyImageButton.disabled = !supported;
    copyImageButton.setAttribute('aria-disabled', supported ? 'false' : 'true');
    copyImageButton.title = mobile ? '手机端图片剪贴板常无法粘贴到微信，请使用直接分享或长按卡片图片' : (supported ? '复制卡片图片，可直接粘贴到聊天窗口' : '当前浏览器暂不支持复制图片，请复制链接分享');
  }

  function updateActionPriority() {
    var buttons = [copyImageButton, shareButton, copyLinkButton];
    buttons.forEach(function (button, index) {
      if (!button) return;
      button.classList.remove('share-card-action--primary');
      button.classList.add('share-card-action--secondary');
      button.style.order = String(index + 2);
    });
    var primary = copyImageButton;
    if (isMobileLike()) {
      primary = canShareImageFile() ? shareButton : copyLinkButton;
    }
    if (!primary) return;
    primary.classList.remove('share-card-action--secondary');
    primary.classList.add('share-card-action--primary');
    primary.style.order = '1';
  }

  function updateHelperText() {
    if (!helperText) return;
    if (isMobileLike()) {
      helperText.textContent = canShareImageFile() ? '手机端建议使用直接分享；如果分享面板没有微信入口，请长按卡片图片保存后发送。' : '手机端图片剪贴板常无法粘贴到微信，请长按卡片图片保存，或复制链接分享。';
    } else {
      helperText.textContent = '复制图片后可直接粘贴到聊天窗口。';
    }
  }

  function isMobileLike() {
    var ua = navigator.userAgent || '';
    var touchScreen = navigator.maxTouchPoints && navigator.maxTouchPoints > 1;
    var narrowScreen = window.matchMedia && window.matchMedia('(max-width: 820px)').matches;
    return /Android|iPhone|iPad|iPod|Mobile|MicroMessenger/i.test(ua) || Boolean(touchScreen && narrowScreen);
  }

  function shareCardImage() {
    if (!canShareImageFile()) {
      showToast('当前浏览器不支持直接分享图片');
      return;
    }
    var title = activeData && activeData.title ? activeData.title : '分享卡片';
    var text = activeData && activeData.excerpt ? activeData.excerpt : title;
    navigator.share({
      title: title,
      text: text,
      files: [activeShareFile]
    }).then(function () {
      showToast('已打开系统分享');
    }).catch(function (err) {
      if (err && err.name === 'AbortError') return;
      showToast('分享失败，请复制图片或链接分享');
    });
  }

  function copyCardImage() {
    if (isMobileLike()) {
      showToast('手机端请长按卡片图片保存或使用直接分享');
      return;
    }
    if (!canCopyImageFile()) {
      showToast('当前浏览器不支持复制图片');
      return;
    }
    navigator.clipboard.write([
      new ClipboardItem({
        'image/png': activeShareFile
      })
    ]).then(function () {
      showToast('图片已复制，可直接粘贴分享');
    }).catch(function () {
      showToast('复制图片失败，请复制链接分享');
    });
  }

  function copyLink() {
    if (!activeData || !activeData.url) return;
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(activeData.url).then(function () {
        showToast('链接已复制');
      }, fallbackCopyLink);
    } else {
      fallbackCopyLink();
    }
  }

  function fallbackCopyLink() {
    var input = document.createElement('textarea');
    input.value = activeData.url;
    input.setAttribute('readonly', '');
    input.style.position = 'fixed';
    input.style.left = '-9999px';
    document.body.appendChild(input);
    input.select();
    try {
      document.execCommand('copy');
      showToast('链接已复制');
    } catch (err) {
      showToast('复制失败，请手动复制链接');
    }
    document.body.removeChild(input);
  }

  function showToast(message) {
    var toast = document.querySelector('.share-card-toast');
    if (!toast) {
      toast = document.createElement('div');
      toast.className = 'share-card-toast';
      toast.setAttribute('role', 'status');
      toast.setAttribute('aria-live', 'polite');
      document.body.appendChild(toast);
    }
    toast.textContent = message;
    toast.classList.add('is-visible');
    clearTimeout(toastTimer);
    toastTimer = setTimeout(function () {
      toast.classList.remove('is-visible');
    }, 2200);
  }

  function filenameFromTitle(title) {
    return title.replace(/[\\/:*?"<>|]+/g, '-').replace(/\s+/g, '-').slice(0, 64) || 'share-card';
  }

  function dataUrlToFile(dataUrl, filename) {
    if (!window.File || !window.Uint8Array || !window.atob) return null;
    var parts = dataUrl.split(',');
    var mimeMatch = parts[0].match(/:(.*?);/);
    var mime = mimeMatch ? mimeMatch[1] : 'image/png';
    var binary = atob(parts[1]);
    var length = binary.length;
    var bytes = new Uint8Array(length);
    for (var i = 0; i < length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    return new File([bytes], filename, { type: mime });
  }

  function renderShareCard(data) {
    var width = 1080;
    var height = 1440;
    var canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    var ctx = canvas.getContext('2d');
    drawCardBackground(ctx, width, height);
    drawBrand(ctx, data);
    var y = 310;
    y = drawWrappedText(ctx, data.title, 92, y, 896, 62, 4, '#172033', '700 56px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif');
    y += 36;
    if (data.excerpt) {
      y = drawWrappedText(ctx, data.excerpt, 92, y, 860, 40, 3, '#516070', '400 30px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif');
      y += 36;
    }
    drawMeta(ctx, data, 92, Math.min(y, 860));
    drawFooter(ctx, data, width, height);
    return canvas.toDataURL('image/png');
  }

  function drawCardBackground(ctx, width, height) {
    ctx.fillStyle = '#eef2f6';
    ctx.fillRect(0, 0, width, height);
    ctx.fillStyle = '#ffffff';
    roundRect(ctx, 54, 54, width - 108, height - 108, 44);
    ctx.fill();
    var gradient = ctx.createLinearGradient(54, 54, 1026, 380);
    gradient.addColorStop(0, '#edf6fb');
    gradient.addColorStop(1, '#ffffff');
    ctx.fillStyle = gradient;
    roundRect(ctx, 54, 54, width - 108, 270, 44, true, false);
    ctx.fill();
    ctx.fillStyle = 'rgba(48, 169, 222, .12)';
    ctx.beginPath();
    ctx.arc(930, 126, 104, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = 'rgba(47, 65, 84, .08)';
    ctx.beginPath();
    ctx.arc(780, 232, 52, 0, Math.PI * 2);
    ctx.fill();
  }

  function drawBrand(ctx, data) {
    ctx.fillStyle = '#2f4154';
    ctx.font = '700 32px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif';
    ctx.fillText(data.siteTitle, 92, 142);
    ctx.fillStyle = '#718096';
    ctx.font = '400 24px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif';
    ctx.fillText(data.siteUrl, 92, 184);
    ctx.fillStyle = '#30a9de';
    roundRect(ctx, 92, 222, 86, 8, 4);
    ctx.fill();
  }

  function drawMeta(ctx, data, x, y) {
    var items = [];
    if (data.date) items.push(data.date);
    if (data.categories.length) items.push(data.categories.join(' / '));
    var meta = items.join('  ·  ');
    ctx.fillStyle = '#718096';
    ctx.font = '400 26px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif';
    if (meta) ctx.fillText(meta, x, y);
    if (data.tags.length) {
      ctx.fillStyle = '#2f4154';
      ctx.font = '500 24px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif';
      drawWrappedText(ctx, data.tags.slice(0, 4).map(function (tag) {
        return '#' + tag;
      }).join('  '), x, y + 54, 820, 34, 2, '#2f4154', '500 24px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif');
    }
  }

  function drawFooter(ctx, data, width, height) {
    var footerY = height - 348;
    ctx.strokeStyle = '#e6ebf0';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(92, footerY - 42);
    ctx.lineTo(width - 92, footerY - 42);
    ctx.stroke();
    var qr = createQrMatrix(data.url);
    drawQr(ctx, qr, 92, footerY, 210);
    ctx.fillStyle = '#172033';
    ctx.font = '700 34px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif';
    ctx.fillText('扫码阅读原文', 344, footerY + 74);
    ctx.fillStyle = '#718096';
    ctx.font = '400 24px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif';
    drawWrappedText(ctx, data.url, 344, footerY + 122, 560, 32, 3, '#718096', '400 24px -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif');
  }

  function drawQr(ctx, matrix, x, y, size) {
    var count = matrix.length;
    var quiet = 4;
    var cells = count + quiet * 2;
    var cell = size / cells;
    ctx.fillStyle = '#ffffff';
    roundRect(ctx, x, y, size, size, 18);
    ctx.fill();
    ctx.fillStyle = '#111827';
    for (var row = 0; row < count; row++) {
      for (var col = 0; col < count; col++) {
        if (!matrix[row][col]) continue;
        ctx.fillRect(x + (col + quiet) * cell, y + (row + quiet) * cell, Math.ceil(cell), Math.ceil(cell));
      }
    }
  }

  function drawWrappedText(ctx, text, x, y, maxWidth, lineHeight, maxLines, color, font) {
    ctx.fillStyle = color;
    ctx.font = font;
    var lines = wrapText(ctx, text, maxWidth, maxLines);
    lines.forEach(function (line, index) {
      ctx.fillText(line, x, y + index * lineHeight);
    });
    return y + lines.length * lineHeight;
  }

  function wrapText(ctx, text, maxWidth, maxLines) {
    var words = String(text || '').split('');
    var lines = [];
    var line = '';
    for (var i = 0; i < words.length; i++) {
      var test = line + words[i];
      if (ctx.measureText(test).width > maxWidth && line) {
        lines.push(line);
        line = words[i];
        if (lines.length === maxLines) break;
      } else {
        line = test;
      }
    }
    if (lines.length < maxLines && line) lines.push(line);
    if (lines.length === maxLines && i < words.length) {
      var last = lines[lines.length - 1];
      while (ctx.measureText(last + '...').width > maxWidth && last.length > 0) {
        last = last.slice(0, -1);
      }
      lines[lines.length - 1] = last + '...';
    }
    return lines;
  }

  function roundRect(ctx, x, y, width, height, radius, topOnly) {
    var r = Math.min(radius, width / 2, height / 2);
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + width - r, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + r);
    if (topOnly) {
      ctx.lineTo(x + width, y + height);
      ctx.lineTo(x, y + height);
    } else {
      ctx.lineTo(x + width, y + height - r);
      ctx.quadraticCurveTo(x + width, y + height, x + width - r, y + height);
      ctx.lineTo(x + r, y + height);
      ctx.quadraticCurveTo(x, y + height, x, y + height - r);
    }
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  function bindWidgets() {
    initGaloisField();
    document.querySelectorAll('.share-card-widget').forEach(function (widget) {
      var trigger = widget.querySelector('.share-card-trigger');
      if (!trigger) return;
      trigger.addEventListener('click', function () {
        var data = getPostData(widget);
        if (!data) {
          showToast('分享卡片数据读取失败');
          return;
        }
        try {
          openModal(data, trigger);
        } catch (err) {
          showToast(err.message || '分享卡片生成失败');
        }
      });
    });
    document.addEventListener('keydown', function (event) {
      if (event.key === 'Escape' && modal && modal.classList.contains('is-open')) {
        closeModal();
      }
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', bindWidgets);
  } else {
    bindWidgets();
  }
})();
